using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors and warnings
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message, string Subcategory)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();
var projectResults = new Dictionary<string, bool>(); // project -> succeeded

void Visit(BaseNode node)
{
    if (node is Microsoft.Build.Logging.StructuredLogger.Error err)
    {
        var proj = FindParentProject(node);
        errors.Add((proj, err.File ?? "", err.LineNumber, err.ColumnNumber, err.Code ?? "", err.Text ?? "", err.Subcategory ?? ""));
    }
    else if (node is Microsoft.Build.Logging.StructuredLogger.Warning warn)
    {
        warnings.Add((FindParentProject(node), warn.File ?? "", warn.LineNumber, warn.ColumnNumber, warn.Code ?? "", warn.Text ?? ""));
    }
    else if (node is Project p)
    {
        var key = p.ProjectFile ?? p.Name ?? "unknown";
        // A project node with errors means it failed
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn)
                Visit(bn);
        }
    }
}

string FindParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p)
            return p.ProjectFile ?? p.Name ?? "unknown";
        if (current is BaseNode bn)
            current = bn.Parent;
        else
            break;
    }
    return "unknown";
}

Visit(build);

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

// Group errors by project
var errorsByProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in errorsByProject)
{
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        var location = !string.IsNullOrEmpty(e.File) ? $"{e.File}({e.Line},{e.Col})" : "(no location)";
        Console.WriteLine($"  {e.Code}: {e.Message}");
        Console.WriteLine($"    at {location}");
    }
    Console.WriteLine();
}

Console.WriteLine("=== BUILD WARNINGS (potentially relevant) ===");
var relevantWarnings = warnings.Where(w =>
    w.Code.StartsWith("NU") || w.Code.StartsWith("MSB") || w.Code.StartsWith("CS") ||
    w.Message.Contains("conflict", StringComparison.OrdinalIgnoreCase) ||
    w.Message.Contains("deprecated", StringComparison.OrdinalIgnoreCase) ||
    w.Message.Contains("not found", StringComparison.OrdinalIgnoreCase)
).GroupBy(w => w.Project);

foreach (var group in relevantWarnings)
{
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var w in group.Take(20))
    {
        Console.WriteLine($"  {w.Code}: {w.Message}");
    }
    Console.WriteLine();
}

// Now let's look at project dependency structure
Console.WriteLine("=== PROJECT STRUCTURE ===");
void VisitProjects(BaseNode node, int depth = 0)
{
    if (node is Project p)
    {
        var hasErrors = false;
        void CheckErrors(BaseNode n)
        {
            if (n is Microsoft.Build.Logging.StructuredLogger.Error) hasErrors = true;
            if (n is TreeNode tn)
                foreach (var c in tn.Children)
                    if (c is BaseNode bn) CheckErrors(bn);
        }
        CheckErrors(p);
        var status = hasErrors ? "FAILED" : "OK";
        Console.WriteLine($"{new string(' ', depth * 2)}[{status}] {p.ProjectFile} (Target: {p.TargetFramework})");
    }
    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn)
                VisitProjects(bn, node is Project ? depth + 1 : depth);
        }
    }
}
VisitProjects(build);

